# Prompt: Using Python: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

def multi_step_checkout(cart_items, discount_code, user, payment_info):
    # Step 1: Validate cart items
    def validate_cart(cart):
        if not cart:
            raise ValueError("Cart is empty")
        for item in cart:
            if item.get('quantity', 0) <= 0:
                raise ValueError("Invalid quantity in cart")
        return True
    
    validate_cart(cart_items)
    
    # Step 2: Apply discount codes
    def apply_discount(cart, code, user):
        valid_codes = {
            'SAVE10': {'discount': 0.1, 'admin_only': False, 'tier_required': None},
            'SAVE20': {'discount': 0.2, 'admin_only': False, 'tier_required': 'premium'},
            'SAVE30': {'discount': 0.3, 'admin_only': True, 'tier_required': None},
            'SAVE50': {'discount': 0.5, 'admin_only': False, 'tier_required': 'vip'}
        }
        
        if code not in valid_codes:
            return cart, 0
            
        code_info = valid_codes[code]
        
        if code_info['admin_only'] and not user.get('is_admin', False):
            raise ValueError("Admin only discount code")
            
        if code_info['tier_required'] and user.get('tier') != code_info['tier_required']:
            raise ValueError("Insufficient user tier for discount code")
            
        total = sum(item.get('price', 0) * item.get('quantity', 0) for item in cart)
        discount_amount = total * code_info['discount']
        return cart, discount_amount
    
    cart_with_discount, discount_amount = apply_discount(cart_items, discount_code, user)
    
    # Step 3: Calculate tax
    def calculate_tax(cart, discount):
        subtotal = sum(item.get('price', 0) * item.get('quantity', 0) for item in cart)
        discounted_total = subtotal - discount
        tax_rate = 0.08
        tax_amount = discounted_total * tax_rate
        return tax_amount
    
    tax_amount = calculate_tax(cart_with_discount, discount_amount)
    
    # Step 4: Process payment
    def process_payment(payment_info, total_amount):
        if not payment_info:
            raise ValueError("Payment information required")
        if payment_info.get('amount') < total_amount:
            raise ValueError("Insufficient payment")
        return True
    
    total_cost = sum(item.get('price', 0) * item.get('quantity', 0) for item in cart_with_discount)
    final_total = total_cost - discount_amount + tax_amount
    process_payment(payment_info, final_total)
    
    # Step 5: Create order record
    def create_order_record(cart, discount, tax, payment_info, user):
        order = {
            'items': cart,
            'discount_applied': discount,
            'tax_amount': tax,
            'total_amount': final_total,
            'payment_method': payment_info.get('method'),
            'user_id': user.get('id'),
            'status': 'completed'
        }
        return order
    
    order_record = create_order_record(cart_with_discount, discount_amount, tax_amount, payment_info, user)
    return order_record